# function_app.py - Azure Functions with Python
import azure.functions as func
import json
import os
from datetime import datetime
from azure.cosmos import CosmosClient

# Initialize Azure Cosmos DB
COSMOS_ENDPOINT = os.environ.get('COSMOS_ENDPOINT')
COSMOS_KEY = os.environ.get('COSMOS_KEY')
cosmos_client = CosmosClient(COSMOS_ENDPOINT, credential=COSMOS_KEY)
database = cosmos_client.get_database_client('UserDatabase')
container = database.get_container_client('Users')

app = func.FunctionApp()

@app.route(route="users", methods=["get", "post"], auth_level=func.AuthLevel.ANONYMOUS)
def users_endpoint(req: func.HttpRequest) -> func.HttpResponse:
    """HTTP trigger function for user management"""

    method = req.method

    if method == "GET":
        # Retrieve all users from Cosmos DB
        users = list(container.read_all_items())

        return func.HttpResponse(
            json.dumps({"users": users, "count": len(users)}),
            mimetype="application/json",
            status_code=200
        )

    elif method == "POST":
        # Parse request body
        req_body = req.get_json()

        if req_body:
            user_data = {
                'id': req_body.get('id', str(datetime.now().timestamp())),
                'name': req_body.get('name', 'Anonymous'),
                'email': req_body.get('email', ''),
                'created_at': datetime.now().isoformat()
            }

            # Insert into Cosmos DB
            container.upsert_item(user_data)

            return func.HttpResponse(
                json.dumps({"message": "User created", "user": user_data}),
                mimetype="application/json",
                status_code=201
            )

        return func.HttpResponse(
            "Invalid request body",
            status_code=400
        )

@app.timer_trigger(schedule="0 0 * * * *", arg_name="myTimer")
def scheduled_cleanup(myTimer: func.TimerRequest) -> None:
    """Scheduled function running daily - demonstrates Azure's Cron service (like GAE Cron)"""

    if myTimer.past_due:
        print("Timer is past due!")

    # Example: Clean up old records
    print("Running scheduled cleanup task")

    # Query and delete old records (older than 30 days)
    cutoff_date = datetime.now().timestamp() - (30 * 24 * 60 * 60)

    for item in container.query_items(
        query="SELECT * FROM Users u WHERE u.created_at < @cutoff",
        parameters=[{"name": "@cutoff", "value": cutoff_date}]
    ):
        container.delete_item(item, item['id'])

    print("Cleanup completed")

